<body>
  <h1>Falling Sand</h1>
  <div class="subtitle">cellular automata sandbox</div>
  <div class="app">
    <div class="canvas-wrap">
      <canvas id="sand" width="500" height="500"></canvas>
    </div>
    <div class="panel">
      <div class="group-title">Materials</div>
      <button class="mat-btn active" id="mat-sand"><span class="swatch" style="background:#e0c068"></span>Sand</button>
      <button class="mat-btn" id="mat-water"><span class="swatch" style="background:#4080ff"></span>Water</button>
      <button class="mat-btn" id="mat-wall"><span class="swatch" style="background:#8c8c96"></span>Wall</button>
      <button class="mat-btn" id="mat-acid"><span class="swatch" style="background:#80ff40"></span>Acid</button>
      <button class="mat-btn" id="mat-empty"><span class="swatch" style="background:#05050a"></span>Eraser</button>
      <button id="clear">Clear All</button>
      <div class="controls-row">
        <button class="ctrl-btn active" id="play-btn">Pause</button>
        <button class="ctrl-btn" id="step-btn">Step</button>
      </div>
      <div class="info">
        <b>Drag</b> to paint.<br>
        Sand sinks through liquids.<br>
        Water spreads sideways.<br>
        Acid dissolves walls &amp; sand.
      </div>
    </div>
  </div>

<script>
(function () {
  "use strict";

  // ---- Grid configuration ----
  const W = 100, H = 100;
  const CELL = 5; // pixels per cell -> 500x500 canvas

  const EMPTY = 0, SAND = 1, WATER = 2, WALL = 3, ACID = 4;
  const NAMES = ["empty", "sand", "water", "wall", "acid"];
  const NAME_TO_ID = { empty: EMPTY, sand: SAND, water: WATER, wall: WALL, acid: ACID };

  const COLORS = [
    [12, 12, 20],     // empty
    [224, 192, 104],  // sand
    [64, 128, 255],   // water
    [140, 140, 150],  // wall
    [128, 255, 64],   // acid
  ];

  const grid = new Uint8Array(W * H);
  const moved = new Uint8Array(W * H);

  const idx = (x, y) => y * W + x;
  const inBounds = (x, y) => x >= 0 && x < W && y >= 0 && y < H;

  // ---- Public API ----
  function get(x, y) {
    if (x < 0 || x >= W || y < 0 || y >= H) return "wall";
    return NAMES[grid[idx(x, y)]];
  }
  function set(x, y, material) {
    if (x < 0 || x >= W || y < 0 || y >= H) return;
    const id = NAME_TO_ID[material];
    if (id === undefined) return;
    grid[idx(x, y)] = id;
  }
  function clear() { grid.fill(EMPTY); }
  function tick(n) {
    n = Math.max(0, Math.floor(n) || 0);
    for (let i = 0; i < n; i++) step();
  }

  window.sim = { w: W, h: H, tick, get, set, clear };

  // ---- Simulation step ----
  function step() {
    moved.fill(0);
    // Process bottom-row-up so each particle moves at most one cell per step.
    for (let y = H - 1; y >= 0; y--) {
      const ltr = Math.random() < 0.5;
      for (let k = 0; k < W; k++) {
        const x = ltr ? k : (W - 1 - k);
        const i = idx(x, y);
        if (moved[i]) continue;
        const m = grid[i];
        if (m === EMPTY || m === WALL) continue;

        if (m === SAND) {
          tryMoveSand(x, y);
        } else if (m === WATER) {
          tryMoveLiquid(x, y, WATER);
        } else if (m === ACID) {
          dissolve(x, y);
          if (moved[i]) continue;
          tryMoveLiquid(x, y, ACID);
        }
      }
    }
  }

  function swap(x1, y1, x2, y2) {
    const i1 = idx(x1, y1), i2 = idx(x2, y2);
    const t = grid[i1];
    grid[i1] = grid[i2];
    grid[i2] = t;
    moved[i1] = 1;
    moved[i2] = 1;
  }

  function tryMoveSand(x, y) {
    const by = y + 1;
    if (by < H) {
      const b = grid[idx(x, by)];
      if (b === EMPTY || b === WATER || b === ACID) { swap(x, y, x, by); return true; }
      const dir = Math.random() < 0.5 ? -1 : 1;
      for (let d = 0; d < 2; d++) {
        const dx = d === 0 ? dir : -dir;
        const nx = x + dx;
        if (nx < 0 || nx >= W) continue;
        const n = grid[idx(nx, by)];
        if (n === EMPTY || n === WATER || n === ACID) { swap(x, y, nx, by); return true; }
      }
    }
    return false;
  }

  function tryMoveLiquid(x, y, type) {
    const by = y + 1;
    if (by < H) {
      const b = grid[idx(x, by)];
      if (b === EMPTY) { swap(x, y, x, by); return true; }
      const dir = Math.random() < 0.5 ? -1 : 1;
      for (let d = 0; d < 2; d++) {
        const dx = d === 0 ? dir : -dir;
        const nx = x + dx;
        if (nx < 0 || nx >= W) continue;
        if (grid[idx(nx, by)] === EMPTY) { swap(x, y, nx, by); return true; }
      }
    }
    // horizontal spread
    const dir = Math.random() < 0.5 ? -1 : 1;
    for (let d = 0; d < 2; d++) {
      const dx = d === 0 ? dir : -dir;
      const nx = x + dx;
      if (nx < 0 || nx >= W) continue;
      if (grid[idx(nx, y)] === EMPTY) { swap(x, y, nx, y); return true; }
    }
    return false;
  }

  function dissolve(x, y) {
    // Acid erodes adjacent sand/wall (below, sides, above).
    const dirs = [[0, 1], [-1, 0], [1, 0], [0, -1]];
    // shuffle
    for (let i = dirs.length - 1; i > 0; i--) {
      const j = (Math.random() * (i + 1)) | 0;
      const t = dirs[i]; dirs[i] = dirs[j]; dirs[j] = t;
    }
    for (const [dx, dy] of dirs) {
      const nx = x + dx, ny = y + dy;
      if (nx < 0 || nx >= W || ny < 0 || ny >= H) continue;
      const ni = idx(nx, ny);
      const t = grid[ni];
      if (t === SAND || t === WALL) {
        if (Math.random() < 0.3) {
          grid[ni] = EMPTY;
          moved[ni] = 1;
        }
      }
    }
  }

  // ---- Rendering ----
  const canvas = document.getElementById('sand');
  canvas.width = W * CELL;
  canvas.height = H * CELL;
  const ctx = canvas.getContext('2d');
  ctx.imageSmoothingEnabled = false;

  const off = document.createElement('canvas');
  off.width = W; off.height = H;
  const offctx = off.getContext('2d');
  const img = offctx.createImageData(W, H);
  const buf = img.data;

  function render() {
    for (let i = 0; i < W * H; i++) {
      const c = COLORS[grid[i]];
      const p = i * 4;
      buf[p] = c[0]; buf[p + 1] = c[1]; buf[p + 2] = c[2]; buf[p + 3] = 255;
    }
    offctx.putImageData(img, 0, 0);
    ctx.drawImage(off, 0, 0, W, H, 0, 0, canvas.width, canvas.height);
  }

  // ---- Animation loop ----
  let running = true;
  function loop() {
    if (running) step();
    render();
    requestAnimationFrame(loop);
  }

  // ---- Painting ----
  let currentMat = SAND;
  const brushR = 2;

  function selectMat(id) {
    currentMat = id;
    document.querySelectorAll('.mat-btn').forEach(b => b.classList.remove('active'));
    const elMap = { [SAND]: 'mat-sand', [WATER]: 'mat-water', [WALL]: 'mat-wall', [ACID]: 'mat-acid', [EMPTY]: 'mat-empty' };
    const el = document.getElementById(elMap[id]);
    if (el) el.classList.add('active');
  }

  function eventToCell(e) {
    const rect = canvas.getBoundingClientRect();
    const cx = (e.clientX - rect.left) / rect.width;
    const cy = (e.clientY - rect.top) / rect.height;
    return [Math.floor(cx * W), Math.floor(cy * H)];
  }

  function paintAt(x, y) {
    const r = brushR;
    for (let dy = -r; dy <= r; dy++) {
      for (let dx = -r; dx <= r; dx++) {
        if (dx * dx + dy * dy <= r * r + 1) {
          const px = x + dx, py = y + dy;
          if (inBounds(px, py)) grid[idx(px, py)] = currentMat;
        }
      }
    }
  }

  let painting = false;
  canvas.addEventListener('mousedown', e => { painting = true; const [x, y] = eventToCell(e); paintAt(x, y); });
  window.addEventListener('mousemove', e => { if (!painting) return; const [x, y] = eventToCell(e); paintAt(x, y); });
  window.addEventListener('mouseup', () => { painting = false; });

  // touch
  canvas.addEventListener('touchstart', e => {
    e.preventDefault(); painting = true;
    const t = e.touches[0]; const [x, y] = eventToCell(t); paintAt(x, y);
  }, { passive: false });
  canvas.addEventListener('touchmove', e => {
    e.preventDefault(); if (!painting) return;
    const t = e.touches[0]; const [x, y] = eventToCell(t); paintAt(x, y);
  }, { passive: false });
  canvas.addEventListener('touchend', () => { painting = false; });

  // ---- UI wiring ----
  document.getElementById('mat-sand').onclick = () => selectMat(SAND);
  document.getElementById('mat-water').onclick = () => selectMat(WATER);
  document.getElementById('mat-wall').onclick = () => selectMat(WALL);
  document.getElementById('mat-acid').onclick = () => selectMat(ACID);
  document.getElementById('mat-empty').onclick = () => selectMat(EMPTY);
  document.getElementById('clear').onclick = () => { clear(); };

  const playBtn = document.getElementById('play-btn');
  playBtn.onclick = () => {
    running = !running;
    playBtn.textContent = running ? 'Pause' : 'Play';
    playBtn.classList.toggle('active', running);
  };
  document.getElementById('step-btn').onclick = () => { step(); };

  // ---- Initial demo content ----
  (function seed() {
    // a little wall structure and some sand to make it instantly satisfying
    for (let x = 30; x < 70; x++) set(x, 70, WALL);
    for (let x = 30; x < 70; x++) set(x, 71, WALL);
    set(50, 69, WALL); set(50, 68, WALL);
    for (let x = 35; x < 48; x++) for (let y = 40; y < 55; y++) set(x, y, SAND);
    for (let x = 52; x < 65; x++) for (let y = 40; y < 55; y++) set(x, y, WATER);
    set(20, 60, ACID); set(21, 60, ACID); set(22, 60, ACID);
  })();

  loop();
})();
</script>
</body>
</html>
